def validate_research_axis(axis, known_decisions):
    # A5: C-TOTALITY: ensure axis is a dict; if not, return failure
    if not isinstance(axis, dict):
        return {"ok": False, "problems": ["axis must be a dict"]}

    problems = []

    # A1: Check all required fields are present
    required_fields = ['axis_id', 'supports_decisions', 'required', 'safe_behavior_if_unknown', 'rdec_ref']
    missing_fields = [f for f in required_fields if f not in axis]
    if missing_fields:
        problems.append(f"Missing required fields: {', '.join(missing_fields)}")
        return {"ok": False, "problems": problems}

    # A2: Validate supports_decisions
    supports_decisions = axis['supports_decisions']
    if not isinstance(supports_decisions, list) or len(supports_decisions) == 0:
        problems.append("supports_decisions must be a non-empty list")
    else:
        for dec_id in supports_decisions:
            if dec_id not in known_decisions:
                problems.append(f"Fabricated decision ID '{dec_id}' in supports_decisions (not in known_decisions)")

    # A3: Validate safe_behavior_if_unknown
    safe_behavior = axis.get('safe_behavior_if_unknown')
    if not isinstance(safe_behavior, str) or safe_behavior == '':
        problems.append("safe_behavior_if_unknown must be a non-empty string")

    # A4: Validate rdec_ref when required is True
    if axis.get('required') is True:
        rdec_ref = axis.get('rdec_ref')
        if not isinstance(rdec_ref, str) or rdec_ref == '':
            problems.append("rdec_ref must be a non-empty string when required is True")

    # Additional validation: axis_id must be non-empty string (implied by A1, but make explicit)
    axis_id = axis.get('axis_id')
    if not isinstance(axis_id, str) or axis_id == '':
        problems.append("axis_id must be a non-empty string")

    # Additional validation: rdec_ref must be non-empty string when present (even if required=False)
    # This addresses the audit concern about missing rdec_ref when required=False
    rdec_ref = axis.get('rdec_ref')
    if rdec_ref is None:
        problems.append("rdec_ref must be present (even if required=False)")
    elif not isinstance(rdec_ref, str) or rdec_ref == '':
        problems.append("rdec_ref must be a non-empty string")

    # If no problems, return success
    if not problems:
        return {"ok": True, "problems": []}
    else:
        return {"ok": False, "problems": problems}
